#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return a > b ? a : b; }

int solve(int i, int j1, int j2, int n, int m, int **grid, int ***dp) {
    if (j1 < 0 || j1 >= m || j2 < 0 || j2 >= m) return -1000000;
    if (i == n - 1) {
        if (j1 == j2) return grid[i][j1];
        else return grid[i][j1] + grid[i][j2];
    }
    if (dp[i][j1][j2] != -1) return dp[i][j1][j2];
    int curr = (j1 == j2) ? grid[i][j1] : grid[i][j1] + grid[i][j2];
    int maxi = -1000000;
    for (int dj1 = -1; dj1 <= 1; dj1++) {
        for (int dj2 = -1; dj2 <= 1; dj2++) {
            int ans = curr + solve(i + 1, j1 + dj1, j2 + dj2, n, m, grid, dp);
            maxi = max(maxi, ans);
        }
    }
    return dp[i][j1][j2] = maxi;
}

int maximumChocolates(int n, int m, int **grid) {
    int ***dp = (int ***)malloc(n * sizeof(int **));
    for (int i = 0; i < n; i++) {
        dp[i] = (int **)malloc(m * sizeof(int *));
        for (int j = 0; j < m; j++) {
            dp[i][j] = (int *)malloc(m * sizeof(int));
            for (int k = 0; k < m; k++) {
                dp[i][j][k] = -1;
            }
        }
    }
    return solve(0, 0, m - 1, n, m, grid, dp);
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int **grid = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        grid[i] = (int *)malloc(m * sizeof(int));
        for (int j = 0; j < m; j++) {
            scanf("%d", &grid[i][j]);
        }
    }
    printf("%d\n", maximumChocolates(n, m, grid));
    return 0;
}

